          valueExperian: byBureau['experian']?.paymentStatus || null,
          valueEquifax: byBureau['equifax']?.paymentStatus || null,
          severity: 'high',
          isDisputable: true,
          disputeRecommendation: 'Payment history differs across bureaus. Request method of verification.',
          createdAt: new Date(),
        });
      }
    }
  }

